RULES = [
    ("missing_edad", lambda r: r.get("edad") is None, "review"),
    ("underage", lambda r: isinstance(r.get("edad"), int) and r["edad"] < 18, "reject"),
    ("ok", lambda r: True, "accept"),
]

def apply_rules(row):
    for name, pred, status in RULES:
        if pred(row):
            return name, status
    return "none", "review"

for row in [{"edad": None}, {"edad": 15}, {"edad": 40}]:
    print(row, "→", apply_rules(row))

