def batch_validate(rows):
    out = []
    for r in rows:
        if r.get("id") is None:
            out.append({**r, "status": "review", "reason": "missing id"})
            continue
        out.append({**r, "status": "accept", "reason": None})
    return out

print(batch_validate([{"id": "C1"}, {"id": None}, {"id": "C2"}]))

